#define BLOCK_SIZE 16

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
void lud_diagonal(float* a, 
                  __local float* local_buf,
                  int size, 
                  int offset)
{
    int i, j, k;
    int local_i = get_local_id(0);

    // Load diagonal block into local memory
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            local_buf[i*BLOCK_SIZE + j] = a[size*(offset + i) + offset + j];
        }
    }

    // Process diagonal block using LU decomposition
    for (i = 0; i < BLOCK_SIZE; i++) {
        if (local_i == i) {
            for (j = i; j < BLOCK_SIZE; j++) {
                float sum = local_buf[i*BLOCK_SIZE + j];
                for (k = 0; k < i; k++) {
                    sum -= local_buf[i*BLOCK_SIZE + k] * local_buf[k*BLOCK_SIZE + j];
                }
                local_buf[i*BLOCK_SIZE + j] = sum;
            }

            float elem = 1.0f / local_buf[i*BLOCK_SIZE + i];
            for (j = i + 1; j < BLOCK_SIZE; j++) {
                float sum = local_buf[j*BLOCK_SIZE + i];
                for (k = 0; k < i; k++) {
                    sum -= local_buf[j*BLOCK_SIZE + k] * local_buf[k*BLOCK_SIZE + i];
                }
                local_buf[j*BLOCK_SIZE + i] = sum * elem;
            }
        }
    }

    // Write back to global memory
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            a[size*(offset + i) + offset + j] = local_buf[i*BLOCK_SIZE + j];
        }
    }
}

__attribute__((reqd_work_group_size(BLOCK_SIZE * 2, 1, 1)))
void lud_perimeter(float* a,
                   __local float* local_buf1,
                   __local float* local_buf2,
                   __local float* local_buf3,
                   int size,
                   int offset)
{
    int local_id = get_local_id(0);
    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;
    int block_idx = local_id / BLOCK_SIZE;
    int elem_idx = local_id % BLOCK_SIZE;

    if (block_idx == 0 && elem_idx < BLOCK_SIZE && local_id < BLOCK_SIZE * num_blocks) {
        // Process right perimeter (upper part)
        int i = elem_idx;
        int j_block = local_id / BLOCK_SIZE;

        // Load diagonal block
        for (int di = 0; di < BLOCK_SIZE; di++) {
            for (int dj = 0; dj < BLOCK_SIZE; dj++) {
                local_buf1[di*BLOCK_SIZE + dj] = a[size*(offset + di) + offset + dj];
            }
        }

        // Load current block row
        for (int j = 0; j < BLOCK_SIZE; j++) {
            local_buf2[i*BLOCK_SIZE + j] = a[size*(offset + i) + offset + BLOCK_SIZE + j_block*BLOCK_SIZE + j];
        }

        // Update
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = local_buf2[i*BLOCK_SIZE + j];
            for (int k = 0; k < i; k++) {
                sum -= local_buf2[i*BLOCK_SIZE + k] * local_buf1[k*BLOCK_SIZE + j];
            }
            local_buf2[i*BLOCK_SIZE + j] = sum;
        }

        // Write back
        for (int j = 0; j < BLOCK_SIZE; j++) {
            a[size*(offset + i) + offset + BLOCK_SIZE + j_block*BLOCK_SIZE + j] = local_buf2[i*BLOCK_SIZE + j];
        }
    }

    if (block_idx == 1 && elem_idx < BLOCK_SIZE && local_id < BLOCK_SIZE * num_blocks + BLOCK_SIZE * num_blocks) {
        // Process lower perimeter (left part)
        int i_block = (local_id - BLOCK_SIZE * num_blocks) / BLOCK_SIZE;
        int j = elem_idx;

        // Load diagonal block
        for (int di = 0; di < BLOCK_SIZE; di++) {
            for (int dj = 0; dj < BLOCK_SIZE; dj++) {
                local_buf3[di*BLOCK_SIZE + dj] = a[size*(offset + di) + offset + dj];
            }
        }

        // Load current block column
        for (int ii = 0; ii < BLOCK_SIZE; ii++) {
            local_buf1[ii*BLOCK_SIZE + j] = a[size*(offset + BLOCK_SIZE + i_block*BLOCK_SIZE + ii) + offset + j];
        }

        // Update
        for (int ii = 0; ii < BLOCK_SIZE; ii++) {
            float sum = local_buf1[ii*BLOCK_SIZE + j];
            for (int k = 0; k < j; k++) {
                sum -= local_buf1[ii*BLOCK_SIZE + k] * local_buf3[k*BLOCK_SIZE + j];
            }
            float denom = local_buf3[j*BLOCK_SIZE + j];
            local_buf1[ii*BLOCK_SIZE + j] = sum / denom;
        }

        // Write back
        for (int ii = 0; ii < BLOCK_SIZE; ii++) {
            a[size*(offset + BLOCK_SIZE + i_block*BLOCK_SIZE + ii) + offset + j] = local_buf1[ii*BLOCK_SIZE + j];
        }
    }
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, BLOCK_SIZE, 1)))
void lud_internal(float* a,
                  __local float* local_buf1,
                  __local float* local_buf2,
                  int size,
                  int offset)
{
    int local_i = get_local_id(0);
    int local_j = get_local_id(1);
    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    // Load diagonal block column
    for (int k = 0; k < BLOCK_SIZE; k++) {
        local_buf1[local_i*BLOCK_SIZE + k] = a[size*(offset + local_i) + offset + k];
    }

    // Load diagonal block row
    for (int k = 0; k < BLOCK_SIZE; k++) {
        local_buf2[k*BLOCK_SIZE + local_j] = a[size*(offset + k) + offset + local_j];
    }

    // Process internal blocks
    for (int i_block = 0; i_block < num_blocks; i_block++) {
        for (int j_block = 0; j_block < num_blocks; j_block++) {
            int global_i = offset + BLOCK_SIZE + i_block*BLOCK_SIZE + local_i;
            int global_j = offset + BLOCK_SIZE + j_block*BLOCK_SIZE + local_j;

            float sum = a[size*global_i + global_j];
            for (int k = 0; k < BLOCK_SIZE; k++) {
                sum -= local_buf1[local_i*BLOCK_SIZE + k] * local_buf2[k*BLOCK_SIZE + local_j];
            }
            a[size*global_i + global_j] = sum;
        }
    }
}
